import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { Receipt } from '../../core/models';

@Component({
  selector: 'app-receipt',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './receipt.component.html',
  styleUrl: './receipt.component.css',
})
export class ReceiptComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Known receipts for the demo tenant. */
  readonly receipts = signal<Receipt[]>([
    { id: 'r1', number: 'R-00001', ledgerEntryId: 'e2', amountCents: 120000, createdAt: '2026-05-03', leaseId: 'l1' },
    { id: 'r2', number: 'R-00002', ledgerEntryId: 'e4', amountCents: 120000, createdAt: '2026-06-04', leaseId: 'l1' },
    { id: 'r3', number: 'R-00003', ledgerEntryId: 'e5', amountCents: 120000, createdAt: '2026-07-12', leaseId: 'l1' },
  ]);

  /** Requested receipt id from the route. */
  private readonly id = signal<string | null>(null);

  /** Resolved receipt, or null when not found. */
  readonly receipt = computed<Receipt | null>(() => {
    const id = this.id();
    if (!id) return null;
    return this.receipts().find((r) => r.id === id) ?? null;
  });

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    // Re-resolve whenever the :id route param changes.
    this.route.paramMap.subscribe((params) => {
      this.id.set(params.get('id'));
    });
  }
}
